@page "/categories"
@page "/categories/{CategorySlug}"

<PageTitle>@(CurrentCategory ?? "All Categories") - RecipeShare</PageTitle>

@if (string.IsNullOrEmpty(CategorySlug))
{
    <h1>All Categories</h1>
    <div class="list-group">
        <a href="categories/appetizers" class="list-group-item list-group-item-action">🥗 Appetizers</a>
        <a href="categories/main-courses" class="list-group-item list-group-item-action">🍝 Main Courses</a>
        <a href="categories/desserts" class="list-group-item list-group-item-action">🍰 Desserts</a>
        <a href="categories/baking" class="list-group-item list-group-item-action">🍞 Baking</a>
        <a href="categories/beverages" class="list-group-item list-group-item-action">🥤 Beverages</a>
        <a href="categories/vegetarian" class="list-group-item list-group-item-action">🥬 Vegetarian</a>
    </div>
}
else
{
    <h1>@CurrentCategory</h1>
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="categories">All Categories</a></li>
            <li class="breadcrumb-item active">@CurrentCategory</li>
        </ol>
    </nav>

    <div class="row">
        @foreach (var recipe in GetRecipesForCategory())
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private string? CurrentCategory => CategorySlug switch
    {
        "appetizers" => "Appetizers",
        "main-courses" => "Main Courses",
        "desserts" => "Desserts",
        "baking" => "Baking",
        "beverages" => "Beverages",
        "vegetarian" => "Vegetarian",
        _ => CategorySlug
    };

    private List<RecipeInfo> GetRecipesForCategory()
    {
        return CategorySlug switch
        {
            "appetizers" => new()
            {
                new(1, "Bruschetta", "Classic Italian toasted bread with tomatoes and basil."),
                new(2, "Stuffed Mushrooms", "Savory mushroom caps filled with herbs and cheese.")
            },
            "main-courses" => new()
            {
                new(3, "Spaghetti Carbonara", "Creamy Italian pasta with eggs, cheese, and pancetta."),
                new(4, "Grilled Salmon", "Fresh salmon fillet with lemon herb butter.")
            },
            "desserts" => new()
            {
                new(5, "Chocolate Lava Cake", "Rich molten chocolate cake with a gooey center."),
                new(6, "Tiramisu", "Classic Italian coffee-flavored layered dessert.")
            },
            "baking" => new()
            {
                new(7, "Sourdough Bread", "Artisan sourdough with a crispy crust."),
                new(8, "Cinnamon Rolls", "Soft, fluffy rolls with cinnamon sugar filling.")
            },
            "beverages" => new()
            {
                new(9, "Mango Smoothie", "Tropical mango blended with yogurt and honey."),
                new(10, "Iced Matcha Latte", "Refreshing green tea latte over ice.")
            },
            "vegetarian" => new()
            {
                new(11, "Vegetable Stir Fry", "Colorful veggies in a savory soy ginger sauce."),
                new(12, "Caprese Salad", "Fresh mozzarella, tomatoes, and basil with balsamic.")
            },
            _ => new()
        };
    }

    private record RecipeInfo(int Id, string Title, string Description);
}

@rendermode InteractiveServer

<div class="star-rating my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= CurrentRating ? "filled" : "")"
              @onclick="() => SetRating(star)"
              role="button"
              title="@star star(s)">
            @(star <= CurrentRating ? "★" : "☆")
        </span>
    }
    @if (CurrentRating > 0)
    {
        <span class="ms-2 text-muted">You rated this @CurrentRating/5</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int CurrentRating { get; set; }

    private void SetRating(int rating)
    {
        CurrentRating = rating;
    }
}

.star-rating {
    display: flex;
    align-items: center;
}

.star {
    font-size: 1.5rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.2s;
}

.star:hover,
.star.filled {
    color: #ffc107;
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h4>Thank you!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been submitted successfully.</p>
        <button class="btn btn-primary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Model.Ingredients"
                placeholder="Enter each ingredient on a new line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
            <div class="form-text">Enter each ingredient on a separate line.</div>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Preparation Steps</label>
            <InputTextArea id="steps" class="form-control" rows="8" @bind-Value="Model.Steps"
                placeholder="Enter each step on a new line&#10;e.g.,&#10;Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
            <div class="form-text">Enter each step on a separate line.</div>
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Model { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        IsSubmitted = true;
    }

    private void ResetForm()
    {
        Model = new();
        IsSubmitted = false;
    }

    private class RecipeSubmission
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please describe the preparation steps.")]
        public string Steps { get; set; } = "";
    }
}

